// ═══════════════════════════════════════════════════════════════════════════════════════

// ───────────────────────────────────────────────────────────────
// 1. INPUT SEGURO — busca en body, query, y root
// ───────────────────────────────────────────────────────────────

var rawInput = $('📥 Receiver POST').first().json;
var input = rawInput.body || rawInput.query || rawInput;

// Forzar que todo sea string donde se espera string
function safeStr(val) {
  if (val === null || val === undefined) return '';
  if (typeof val === 'number') return String(val);
  if (typeof val !== 'string') return '';
  return val;
}

function safeTrim(val) {
  return safeStr(val).trim();
}

// ───────────────────────────────────────────────────────────────
// 2. SANITIZACIÓN — prevenir XSS e inyección
// ───────────────────────────────────────────────────────────────

function sanitize(str) {
  if (!str) return '';
  return str
    .replace(/</g, '')
    .replace(/>/g, '')
    .replace(/"/g, '')
    .replace(/'/g, '')
    .replace(/`/g, '')
    .replace(/\\/g, '')
    .replace(/javascript:/gi, '')
    .replace(/on\w+=/gi, '')
    .trim();
}

// ───────────────────────────────────────────────────────────────
// 3. EXTRACTOR DE NOMBRE — MEGA BLINDADO
// ───────────────────────────────────────────────────────────────

var TITULOS = [
  'dr', 'dra', 'doctor', 'doctora',
  'lic', 'licdo', 'licda', 'licenciado', 'licenciada',
  'ing', 'ingeniero', 'ingeniera',
  'arq', 'arquitecto', 'arquitecta',
  'abog', 'abogado', 'abogada',
  'prof', 'profesor', 'profesora',
  'sr', 'sra', 'srta', 'señor', 'señora', 'señorita',
  'mr', 'mrs', 'ms', 'miss',
  'coach', 'mtr', 'mtro', 'mtra', 'maestro', 'maestra',
  'phd', 'md', 'mba', 'cpa', 'ceo', 'cfo', 'cto', 'coo',
  'ps', 'psi', 'psicologo', 'psicologa',
  'cp', 'contador', 'contadora',
  'mons', 'fray', 'sor', 'padre', 'hermano', 'hermana',
  'gral', 'general', 'cap', 'capitan', 'tte', 'teniente',
  'cmdte', 'comandante', 'sargento', 'cabo'
];

var PARTICULAS = [
  'de', 'del', 'la', 'las', 'los', 'el',
  'van', 'von', 'der', 'den', 'het',
  'di', 'da', 'do', 'dos', 'das',
  'al', 'bin', 'ibn', 'abu',
  'mac', 'mc', 'le', 'du', 'des', 'san', 'santa', 'santo'
];

// Apellidos hispanos comunes (para detectar orden invertido)
var APELLIDOS_COMUNES = [
  'garcia', 'rodriguez', 'martinez', 'lopez', 'gonzalez', 'hernandez',
  'perez', 'sanchez', 'ramirez', 'torres', 'flores', 'rivera',
  'gomez', 'diaz', 'reyes', 'morales', 'jimenez', 'ruiz',
  'alvarez', 'romero', 'mendoza', 'gutierrez', 'ortiz', 'castillo',
  'vargas', 'moreno', 'castro', 'ramos', 'herrera', 'medina',
  'aguilar', 'pena', 'vega', 'cruz', 'dominguez', 'leon',
  'rojas', 'soto', 'navarro', 'mejia', 'silva', 'delgado',
  'cabrera', 'rios', 'contreras', 'fuentes', 'cardenas', 'guerrero',
  'campos', 'santos', 'salazar', 'nunez', 'estrada', 'acosta',
  'figueroa', 'cervantes', 'velasquez', 'valenzuela', 'pacheco', 'espinoza',
  'sandoval', 'ibarra', 'maldonado', 'gallegos', 'villanueva', 'trejo',
  'smith', 'johnson', 'williams', 'brown', 'jones', 'davis', 'miller',
  'wilson', 'moore', 'taylor', 'anderson', 'thomas', 'jackson', 'white'
];

function normalizeForComparison(str) {
  return str.toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z]/g, '');
}

function extraerPrimerNombre(nombreCompleto) {
  if (!nombreCompleto || typeof nombreCompleto !== 'string') return null;

  // Paso 1: Limpiar agresivamente
  var limpio = nombreCompleto
    .replace(/[\u{1F000}-\u{1FFFF}]/gu, '')   // emojis bloque 1
    .replace(/[\u{2600}-\u{27BF}]/gu, '')      // emojis misc
    .replace(/[\u{FE00}-\u{FEFF}]/gu, '')      // variation selectors
    .replace(/[\u{200B}-\u{200D}]/gu, '')      // zero-width chars
    .replace(/[0-9]/g, '')                      // números
    .replace(/[@#$%^&*()+=\[\]{}<>|~_]/g, '')  // símbolos
    .replace(/[.,;:!?]/g, '')                   // puntuación
    .replace(/\s+/g, ' ')                       // múltiples espacios
    .trim();

  if (!limpio || limpio.length < 1) return null;

  // Paso 2: Dividir en partes
  var partes = limpio.split(' ').filter(function(p) { return p.length > 0; });
  if (!partes.length) return null;

  // Paso 3: Si solo hay una parte, esa es el nombre
  if (partes.length === 1) {
    return capitalizar(partes[0]);
  }

  // Paso 4: Normalizar para comparar
  var partesNorm = partes.map(function(p) { return normalizeForComparison(p); });

  // Paso 5: Detectar si el primer elemento es apellido (orden invertido)
  // Ej: "García López María" → tomar "María"
  if (partes.length >= 3) {
    var primeraNorm = partesNorm[0];
    var segundaNorm = partesNorm[1];
    var ultimaNorm = partesNorm[partes.length - 1];

    var primeraEsApellido = APELLIDOS_COMUNES.indexOf(primeraNorm) !== -1;
    var segundaEsApellido = APELLIDOS_COMUNES.indexOf(segundaNorm) !== -1;
    var ultimaEsApellido = APELLIDOS_COMUNES.indexOf(ultimaNorm) !== -1;

    // Si las dos primeras son apellidos y la última no, tomar la última
    if (primeraEsApellido && segundaEsApellido && !ultimaEsApellido) {
      return capitalizar(partes[partes.length - 1]);
    }
  }

  // Paso 6: Saltar títulos
  var idx = 0;
  while (idx < partes.length - 1 && TITULOS.indexOf(partesNorm[idx]) !== -1) {
    idx++;
  }

  // Paso 7: Saltar partículas (solo si hay algo después)
  while (idx < partes.length - 1 && PARTICULAS.indexOf(partesNorm[idx]) !== -1) {
    idx++;
  }

  // Paso 8: Verificar si lo que encontramos es apellido conocido
  // y hay algo después que no lo es
  if (idx < partes.length - 1 && APELLIDOS_COMUNES.indexOf(partesNorm[idx]) !== -1) {
    var nextIdx = idx + 1;
    // Saltar partículas después del apellido
    while (nextIdx < partes.length - 1 && PARTICULAS.indexOf(partesNorm[nextIdx]) !== -1) {
      nextIdx++;
    }
    if (APELLIDOS_COMUNES.indexOf(partesNorm[nextIdx]) === -1) {
      // El siguiente no es apellido, pero esto ya es raro, mantener idx original
    }
  }

  // Paso 9: Safety — si nos pasamos de índice
  if (idx >= partes.length) idx = 0;

  return capitalizar(partes[idx]);
}

function capitalizar(str) {
  if (!str || str.length === 0) return '';

  str = str.toLowerCase();

  // Manejar apóstrofes: O'connor → O'Connor | D'angelo → D'Angelo
  if (str.includes("'")) {
    return str.split("'").map(function(part) {
      if (part.length === 0) return '';
      return part.charAt(0).toUpperCase() + part.slice(1);
    }).join("'");
  }

  // Manejar guiones: jean-pierre → Jean-Pierre | mary-jane → Mary-Jane
  if (str.includes('-')) {
    return str.split('-').map(function(part) {
      if (part.length === 0) return '';
      return part.charAt(0).toUpperCase() + part.slice(1);
    }).join('-');
  }

  // Normal
  return str.charAt(0).toUpperCase() + str.slice(1);
}

// ───────────────────────────────────────────────────────────────
// 4. EXTRAER NOMBRE DESDE EMAIL (fallback)
// ───────────────────────────────────────────────────────────────

function nombreDesdeEmail(email) {
  if (!email || typeof email !== 'string') return null;

  var localPart = email.split('@')[0];
  if (!localPart) return null;

  // Quitar números y caracteres especiales
  var limpio = localPart
    .replace(/[0-9]/g, '')
    .replace(/[._+\-]/g, ' ')
    .trim();

  var partes = limpio.split(' ').filter(function(p) { return p.length > 1; });
  if (!partes.length) return null;

  return capitalizar(partes[0]);
}

// ───────────────────────────────────────────────────────────────
// 5. NORMALIZAR PLATAFORMA
// ───────────────────────────────────────────────────────────────

function normalizarPlataforma(platform) {
  if (!platform || typeof platform !== 'string') return 'meet';

  var p = platform.toLowerCase().trim()
    .replace(/\s+/g, '')
    .replace(/[^a-z]/g, '');

  // Zoom
  if (p === 'zoom' || p === 'zoommeeting' || p === 'zoomcall') return 'zoom';

  // Meet
  if (p === 'meet' || p === 'googlemeet' || p === 'gmeet' || p === 'googlemeeting' || p === 'hangouts' || p === 'hangout') return 'meet';

  return 'meet';
}

// ───────────────────────────────────────────────────────────────
// 6. NORMALIZAR TELÉFONO
// ───────────────────────────────────────────────────────────────

function normalizarTelefono(phone) {
  if (!phone) return null;
  var limpio = safeStr(phone).replace(/[^0-9+\-() ]/g, '').trim();
  if (limpio.length < 7) return null;
  return limpio;
}

// ───────────────────────────────────────────────────────────────
// 7. VALIDACIONES
// ───────────────────────────────────────────────────────────────

var errors = [];

var rawName = safeTrim(input.fullName);
var rawEmail = safeTrim(input.email);
var rawPlatform = safeTrim(input.platform);
var rawDate = safeTrim(input.date);
var rawTime = safeTrim(input.time);
var rawBusiness = safeTrim(input.business);
var rawNeed = safeTrim(input.need);
var rawPhone = input.phone;
var rawTimezone = safeTrim(input.timezone);
var rawSource = safeTrim(input.source);
var rawLeadId = safeTrim(input.leadId);
var rawDateFormatted = safeTrim(input.dateFormatted);

// Nombre
if (!rawName || rawName.length < 1) {
  // Intentar extraer del email
  if (rawEmail) {
    var emailName = nombreDesdeEmail(rawEmail);
    if (emailName) {
      rawName = emailName;
    } else {
      errors.push('Nombre invalido');
    }
  } else {
    errors.push('Nombre invalido');
  }
}

// Email
if (!rawEmail || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(rawEmail)) {
  errors.push('Email invalido');
}

// Plataforma
var platform = normalizarPlataforma(rawPlatform);

// Fecha y hora
if (!rawDate || !rawTime) {
  errors.push('Fecha u hora no especificada');
}

// Validar formato de hora
if (rawTime && !/^\d{1,2}:\d{2}$/.test(rawTime)) {
  errors.push('Formato de hora invalido');
}

// Negocio
if (!rawBusiness || rawBusiness.length < 2) {
  errors.push('Negocio no especificado');
}

// Necesidad
if (!rawNeed || rawNeed.length < 5) {
  errors.push('Necesidad no especificada');
}

// ───────────────────────────────────────────────────────────────
// 8. CONSTRUIR FECHA/HORA — FORTRESS
// ───────────────────────────────────────────────────────────────

var timezone = rawTimezone || 'America/Mexico_City';
var meetingStart = null;
var meetingEnd = null;

if (rawDate && rawTime && rawTime.includes(':')) {
  try {
    var dateObj = new Date(rawDate);

    // Validar que la fecha es válida
    if (isNaN(dateObj.getTime())) {
      errors.push('Fecha no reconocida');
    } else {
      var timeParts = rawTime.split(':');
      var hours = parseInt(timeParts[0], 10);
      var minutes = parseInt(timeParts[1], 10);

      // Validar rango de horas
      if (hours < 0 || hours > 23 || minutes < 0 || minutes > 59) {
        errors.push('Hora fuera de rango');
      } else {
        meetingStart = new Date(dateObj);
        meetingStart.setHours(hours, minutes, 0, 0);

        meetingEnd = new Date(meetingStart.getTime() + 30 * 60000);

        // No permitir pasado
        var now = new Date();
        if (meetingStart.getTime() <= now.getTime()) {
          errors.push('El horario seleccionado ya paso');
        }

        // No permitir mas de 3 meses adelante
        var maxDate = new Date();
        maxDate.setMonth(maxDate.getMonth() + 3);
        if (meetingStart.getTime() > maxDate.getTime()) {
          errors.push('La fecha esta muy lejos en el futuro');
        }

        // No permitir madrugada (opcional: 00:00 a 06:59)
        if (hours < 7) {
          errors.push('No se agendan llamadas antes de las 7:00');
        }

        // No permitir después de las 22:00
        if (hours >= 22) {
          errors.push('No se agendan llamadas despues de las 22:00');
        }
      }
    }
  } catch (e) {
    errors.push('Error procesando fecha: ' + e.message);
  }
}

var isValid = errors.length === 0;

// ───────────────────────────────────────────────────────────────
// 9. FORMATEAR FECHAS
// ───────────────────────────────────────────────────────────────

function formatForZoom(date) {
  if (!date) return null;
  return date.toISOString().replace('.000Z', 'Z');
}

function formatForCalendar(date) {
  if (!date) return null;
  return date.toISOString();
}

// ───────────────────────────────────────────────────────────────
// 10. CONSTRUIR DATOS FINALES
// ───────────────────────────────────────────────────────────────

var fullName = sanitize(rawName);
var firstName = extraerPrimerNombre(fullName) || nombreDesdeEmail(rawEmail) || 'Estimado';
var leadId = sanitize(rawLeadId) || 'nx-' + Date.now();
var email = rawEmail.toLowerCase().trim();
var phone = normalizarTelefono(rawPhone);
var business = sanitize(rawBusiness);
var need = sanitize(rawNeed);
var source = sanitize(rawSource) || 'landing-nexus';
var dateFormatted = sanitize(rawDateFormatted);

// Protocol URL
var protocolUrl = 'https://nexusys.duckdns.org/webhook/protocol-start?leadId=' + encodeURIComponent(leadId) + '&email=' + encodeURIComponent(email);

// Calendar body para Meet HTTP request
var calendarBody = JSON.stringify({
  summary: 'Nexus - ' + fullName.substring(0, 50),
  description: 'Nombre: ' + fullName + '\nEmail: ' + email + '\nNegocio: ' + business + '\nNecesidad: ' + need,
  start: {
    dateTime: formatForCalendar(meetingStart),
    timeZone: timezone
  },
  end: {
    dateTime: formatForCalendar(meetingEnd),
    timeZone: timezone
  },
  attendees: [
    { email: email }
  ],
  conferenceData: {
    createRequest: {
      requestId: 'nexus-' + Date.now() + '-' + Math.random().toString(36).substring(2, 8),
      conferenceSolutionKey: { type: 'hangoutsMeet' }
    }
  },
  reminders: {
    useDefault: false,
    overrides: [
      { method: 'email', minutes: 60 },
      { method: 'popup', minutes: 15 }
    ]
  }
});

// Telegram
var telegramMessage = '*Nueva Cita Agendada*\n\n' +
  'Nombre: ' + fullName + '\n' +
  'Email: ' + email + '\n' +
  'Negocio: ' + business + '\n' +
  'Plataforma: ' + platform + '\n' +
  'Fecha: ' + dateFormatted + '\n' +
  'Hora: ' + (rawTime || '');

// Sheet
var sheet = {
  Timestamp: new Date().toISOString(),
  LeadID: leadId,
  Nombre: fullName,
  Email: email,
  Negocio: business,
  Necesidad: need,
  Plataforma: platform,
  Fecha: dateFormatted,
  Hora: rawTime || '',
  MeetLink: '',
  Fuente: source,
  Estado: 'Agendada'
};

// ───────────────────────────────────────────────────────────────
// 11. OUTPUT
// ───────────────────────────────────────────────────────────────

return [{
  json: {
    isValid: isValid,
    errors: errors,

    lead: {
      id: leadId,
      fullName: fullName,
      firstName: firstName,
      email: email,
      phone: phone,
      business: business,
      need: need,
      platform: platform,
      source: source
    },

    meeting: {
      start: formatForZoom(meetingStart),
      end: formatForCalendar(meetingEnd),
      duration: 30,
      timezone: timezone,
      dateFormatted: dateFormatted,
      time: rawTime || ''
    },

    protocolUrl: protocolUrl,
    calendarBody: calendarBody,
    telegramChatId: '6324940125',
    telegramMessage: telegramMessage,
    sheet: sheet,

    _audit: {
      version: 'v6.0-MEGA-BLINDADO',
      processedAt: new Date().toISOString(),
      nameExtraction: {
        rawInput: rawName,
        extracted: firstName,
        method: rawName ? 'fullName' : (rawEmail ? 'email-fallback' : 'default'),
        fullNameLength: fullName.length
      },
      platformNormalized: platform,
      rawPlatformInput: rawPlatform,
      inputSource: rawInput.body ? 'body' : (rawInput.query ? 'query' : 'root'),
      validationErrors: errors.length,
      hasPhone: !!phone
    }
  }
}];

// ⚙️ CALCULAR SLOTS - Filtra horarios pasados del día actual

const webhookData = $('📅 GET Disponibilidad1').first().json;
const calendarEvents = $('📆 Leer Eventos').all();

// Parámetros del request
const year = parseInt(webhookData.query?.year) || new Date().getFullYear();
const month = parseInt(webhookData.query?.month) || new Date().getMonth() + 1;
const userTz = webhookData.query?.tz || 'America/Mexico_City';

// Configuración
const CONFIG = {
  startHour: 9,
  endHour: 18,
  slotMinutes: 30,
  blockedDays: [0], // Domingo
  minAdvanceMinutes: 60 // Mínimo 1 hora de anticipación
};

// Obtener hora actual en zona horaria del usuario
function getNowInTz(tz) {
  const now = new Date();
  const formatter = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  });
  const parts = formatter.formatToParts(now);
  const get = (type) => parts.find(p => p.type === type)?.value || '0';
  return {
    year: parseInt(get('year')),
    month: parseInt(get('month')),
    day: parseInt(get('day')),
    hour: parseInt(get('hour')),
    minute: parseInt(get('minute'))
  };
}

// Generar slots del día
function generateDaySlots() {
  const slots = [];
  for (let h = CONFIG.startHour; h < CONFIG.endHour; h++) {
    for (let m = 0; m < 60; m += CONFIG.slotMinutes) {
      slots.push(`${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}`);
    }
  }
  return slots;
}

// Verificar si slot está ocupado
function isSlotBusy(dateStr, time, events) {
  const slotStart = new Date(`${dateStr}T${time}:00`);
  const slotEnd = new Date(slotStart.getTime() + CONFIG.slotMinutes * 60000);

  for (const event of events) {
    const startDT = event.json?.start?.dateTime;
    const endDT = event.json?.end?.dateTime;
    if (!startDT || !endDT) continue;

    const eventStart = new Date(startDT);
    const eventEnd = new Date(endDT);

    if (slotStart < eventEnd && slotEnd > eventStart) {
      return true;
    }
  }
  return false;
}

// === CALCULAR DISPONIBILIDAD ===
const now = getNowInTz(userTz);
const availability = {};
const daysInMonth = new Date(year, month, 0).getDate();

for (let day = 1; day <= daysInMonth; day++) {
  const dateStr = `${year}-${String(month).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
  const date = new Date(year, month - 1, day);
  const dayOfWeek = date.getDay();

  // Saltar domingos
  if (CONFIG.blockedDays.includes(dayOfWeek)) continue;

  // Verificar si es hoy o pasado
  const isToday = (year === now.year && month === now.month && day === now.day);
  const isPast = (year < now.year) ||
                 (year === now.year && month < now.month) ||
                 (year === now.year && month === now.month && day < now.day);

  if (isPast) continue;

  // Generar slots
  let slots = generateDaySlots();

  // ⭐ FILTRO CLAVE: Si es HOY, quitar slots pasados
  if (isToday) {
    const currentMinutes = now.hour * 60 + now.minute + CONFIG.minAdvanceMinutes;
    slots = slots.filter(time => {
      const [h, m] = time.split(':').map(Number);
      return (h * 60 + m) > currentMinutes;
    });
  }

  // Filtrar slots ocupados por eventos del calendario
  slots = slots.filter(time => !isSlotBusy(dateStr, time, calendarEvents));

  if (slots.length > 0) {
    availability[dateStr] = slots;
  }
}

return [{
  json: {
    availability,
    timezone: userTz,
    generated: new Date().toISOString(),
    currentTime: `${now.hour}:${String(now.minute).padStart(2,'0')}`
  }
}];

const allInputs = $input.all();
const brainData = $('🧠 Brain').first().json;

// ═══════════════════════════════════════════════════════════════
// CONFIGURATION
// ═══════════════════════════════════════════════════════════════

const CONFIG = {
  brand: {
    name: 'Nexus',
    color: '#2563eb',
    sender: 'Santiago'
  },
  protocolBaseUrl: 'https://nexusys.duckdns.org/webhook/protocol-start',
  nombresFemeninos: new Set([
    'maria','ana','carmen','laura','patricia','andrea','lucia','sofia','isabel','rosa',
    'elena','paula','gabriela','daniela','alejandra','victoria','valentina','camila',
    'mariana','carolina','fernanda','monica','veronica','adriana','diana','claudia',
    'sandra','silvia','lorena','paola','natalia','marcela','cecilia','susana','martha',
    'gloria','teresa','julia','beatriz','rocio','cristina','alicia','karla','karen',
    'jessica','jennifer','michelle','melissa','vanessa','viviana','ximena','jimena',
    'regina','renata','emma','olivia','isabella','valeria','catalina','samantha'
  ])
};

// ═══════════════════════════════════════════════════════════════
// UTILITIES
// ═══════════════════════════════════════════════════════════════

function random(arr) { 
  return arr && arr.length ? arr[Math.floor(Math.random() * arr.length)] : ''; 
}

function escapeHtml(str) {
  if (!str || typeof str !== 'string') return '';
  return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

// ═══════════════════════════════════════════════════════════════
// LINK EXTRACTOR - BUSCA EN MÚLTIPLES FUENTES
// ═══════════════════════════════════════════════════════════════

function extractLink(response) {
  if (!response) return '';
  if (response.error || response.code >= 400) return '';

  // Zoom
  if (response.join_url) return response.join_url;

  // Google Meet - hangoutLink
  if (response.hangoutLink) return response.hangoutLink;

  // Google Meet - conferenceData
  if (response.conferenceData && response.conferenceData.entryPoints) {
    const video = response.conferenceData.entryPoints.find(function(e) { 
      return e.entryPointType === 'video'; 
    });
    if (video && video.uri) return video.uri;
  }

  return '';
}

function findMeetLink() {
  // 1. Buscar en inputs directos
  for (var i = 0; i < allInputs.length; i++) {
    var link = extractLink(allInputs[i].json);
    if (link) return link;
  }

  // 2. Buscar en nodos específicos
  var nodesToCheck = ['📆 Crear Evento Meet', '📆 Crear Evento Zoom', '📅 Crear Meet1', '📅 Crear Zoom1'];

  for (var j = 0; j < nodesToCheck.length; j++) {
    try {
      var nodeData = $(nodesToCheck[j]).first();
      if (nodeData && nodeData.json) {
        var link = extractLink(nodeData.json);
        if (link) return link;
      }
    } catch (e) {
      // Nodo no existe, continuar
    }
  }

  return '';
}

function detectLinkType(url) {
  if (!url) return 'unknown';
  if (url.includes('zoom.us')) return 'zoom';
  if (url.includes('meet.google.com')) return 'meet';
  return 'video';
}

function getLinkLabel(type) {
  if (type === 'zoom') return 'Zoom';
  if (type === 'meet') return 'Google Meet';
  return 'Videollamada';
}

// ═══════════════════════════════════════════════════════════════
// GENDER DETECTOR
// ═══════════════════════════════════════════════════════════════

function detectGender(firstName) {
  if (!firstName) return 'neutral';
  var name = firstName.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (CONFIG.nombresFemeninos.has(name)) return 'femenino';
  if (name.endsWith('a') && name.length > 3) return 'femenino';
  return 'neutral';
}

